INSERT INTO months_info (month, wake_window_min, wake_window_max, feed_amount_min, feed_amount_max, daily_feed_total, nap_count, total_sleep_hours, feed_count, summary) VALUES
(0, 30, 60, 40, 80, 500, '수시', '16~18', '8~12회', '신생아 시기로, 하루 대부분을 잠으로 보냅니다. 수유와 수면의 구분이 뚜렷하지 않으며, 2~3시간 간격으로 수유가 필요합니다. 모로반사, 파악반사 등 원시반사가 나타나는 시기입니다.'),
(1, 45, 75, 80, 120, 700, '4~5회', '15~17', '7~8회', '시선을 고정하고 가까운 거리의 사물을 바라볼 수 있습니다. 엎드리면 잠깐 고개를 들어올리는 시도를 하며, 사회적 미소가 시작됩니다. 울음 외에 ''쿠잉'' 소리를 내기 시작합니다.'),
(2, 60, 90, 120, 150, 800, '4~5회', '14~16', '6~7회', '목 가누기가 조금씩 안정되기 시작합니다. 눈앞의 물체를 따라 시선을 이동하고, 소리 나는 방향으로 고개를 돌립니다. 옹알이가 활발해지며 양육자의 얼굴을 보고 웃는 빈도가 늘어납니다.'),
(3, 75, 120, 150, 180, 850, '3~4회', '14~16', '5~6회', '목 가누기가 안정되고, 손을 뻗어 물건을 잡으려 시도합니다. 옹알이가 더욱 다양해지며 사회적 미소가 뚜렷해집니다. 터미타임을 통해 상체 근력을 기를 수 있는 중요한 시기입니다.'),
(4, 90, 150, 180, 210, 900, '3~4회', '14~15', '5~6회', '손으로 물건을 잡아 입으로 가져가는 탐색 행동이 시작됩니다. 뒤집기를 시도하거나 성공하는 아기도 있습니다. 낯선 사람과 친숙한 사람을 구별하기 시작하며, 감정 표현이 풍부해집니다.'),
(5, 120, 150, 180, 210, 900, '3회', '14~15', '4~5회', '뒤집기가 능숙해지고, 앉히면 잠깐 혼자 앉는 자세를 유지하려 합니다. 물건을 양손으로 옮기며 촉각 탐색이 활발해집니다. 이유식 시작을 준비하는 시기로 음식에 관심을 보이기 시작합니다.'),
(6, 120, 180, 180, 210, 800, '2~3회', '13~14', '4~5회', '혼자 앉기가 가능해지고, 이유식을 본격적으로 시작합니다. 낯가림이 뚜렷해지며 주 양육자에 대한 애착이 강해집니다. ''마마'', ''다다'' 등 자음+모음 조합의 옹알이가 나타납니다.'),
(7, 150, 210, 180, 210, 800, '2회', '13~14', '3~4회', '배밀이나 기기를 시작하며 이동 범위가 넓어집니다. 엄지와 검지로 작은 물건을 집는 미세 운동이 발달합니다. 까꿍놀이를 이해하고 즐기며, 대상 영속성 개념이 형성되기 시작합니다.'),
(8, 150, 210, 180, 210, 700, '2회', '13~14', '3~4회', '잡고 서기를 시도하며, 가구를 붙잡고 이동하는 크루징을 합니다. 간단한 단어의 의미를 이해하기 시작합니다. 이유식 중기로 다양한 식재료를 경험시키는 것이 중요합니다.'),
(9, 180, 240, 180, 210, 600, '2회', '13~14', '3회', '기기가 능숙해지고, 잡고 서기가 안정됩니다. ''안돼''라는 말에 반응하며, 손가락으로 원하는 것을 가리킵니다. 분리불안이 가장 심한 시기로, 안정적인 애착 형성이 중요합니다.'),
(10, 180, 240, 180, 210, 600, '2회', '13~14', '2~3회', '혼자 서기를 시도하고, 첫 걸음을 떼는 아기도 있습니다. 간단한 지시(''줘'', ''이리 와'')를 이해하고 따릅니다. 컵으로 마시기 연습을 시작하며, 자기 주도 식사에 관심을 보입니다.'),
(11, 210, 300, 180, 210, 500, '2회', '13~14', '2~3회', '혼자 서거나 벽을 짚고 걷는 것이 능숙해집니다. ''맘마'', ''빠빠'' 등 의미 있는 첫 단어가 나타나기 시작합니다. 손가락 소근육이 발달하여 블록 쌓기나 간단한 조작 놀이가 가능해집니다.'),
(12, 210, 300, 180, 210, 400, '1~2회', '12~14', '2~3회', '첫 걸음을 떼거나 걷기가 시작되는 아기가 많습니다. 1~3개의 단어를 말할 수 있고, 더 많은 단어를 이해합니다. 숟가락을 직접 사용하려 하며, 자아 인식의 첫 단계가 나타납니다.');
INSERT INTO wonder_weeks (week_number, start_day, end_day, title, description) VALUES
(1, 31, 38, '감각의 세계', '생후 5주경, 아기의 감각이 급격히 발달하는 시기입니다. 세상이 더 또렷하게 보이고 들리기 시작하면서 아기가 낯설어하고 불안해할 수 있습니다. 평소보다 더 많이 울고, 안아달라고 보채며, 수유량이 일시적으로 변할 수 있습니다. 충분히 안아주고 피부 접촉을 늘려 안정감을 주세요.'),
(2, 49, 59, '패턴의 세계', '생후 8주경, 아기가 반복되는 패턴을 인식하기 시작합니다. 자신의 손을 발견하고, 단순한 패턴(줄무늬, 흑백 모빌)에 관심을 보입니다. 보채는 시간이 늘고 수면 패턴이 무너질 수 있습니다. 흑백 그림이나 모빌을 보여주고, 규칙적인 일과를 유지해 주세요.'),
(3, 77, 88, '부드러운 전환의 세계', '생후 12주경, 움직임이 부드러워지고 세상의 변화를 감지합니다. 목소리 톤의 변화, 빛의 밝기 변화 등을 인식하기 시작합니다. 갑자기 심하게 울거나 잠을 잘 자지 않을 수 있습니다. 다양한 소리와 음악을 들려주고, 부드러운 터치 놀이를 해 주세요.'),
(4, 101, 137, '사건의 세계', '생후 19주경, 아기가 연속된 사건을 이해하기 시작합니다. 물건을 떨어뜨리면 소리가 난다는 인과관계를 파악합니다. 밤잠이 불안정해지고 낮잠을 거부할 수 있습니다. 가장 긴 도약기 중 하나로 1~6주간 지속될 수 있습니다. 원인과 결과를 보여주는 놀이(딸랑이, 소리 나는 장난감)를 활용하세요.'),
(5, 158, 186, '관계의 세계', '생후 26주경, 사물 간의 관계(거리, 위치)를 이해하기 시작합니다. 물건이 손에서 떨어지면 찾아보고, 엄마가 멀어지면 불안해합니다. 분리불안이 나타나며, 보채거나 매달리는 행동이 증가합니다. 까꿍놀이로 대상 영속성을 경험하게 하고, 떨어져도 돌아온다는 안정감을 심어주세요.'),
(6, 238, 263, '분류의 세계', '생후 37주경, 사물을 분류하는 능력이 생깁니다. 음식과 장난감을 구별하고, 동물과 사람을 다르게 인식합니다. 낯가림이 더 심해지고, 특정 장난감이나 물건에 집착할 수 있습니다. 다양한 질감의 장난감을 제공하고, 같은/다른 것을 알려주는 놀이를 해 주세요.'),
(7, 294, 326, '순서의 세계', '생후 46주경, 행동의 순서를 이해하기 시작합니다. 블록을 쌓고 무너뜨리기, 뚜껑 열고 닫기 등 순차적 행동을 즐깁니다. 떼를 쓰거나 화를 내는 빈도가 늘어날 수 있습니다. 단계적인 놀이(컵 쌓기, 링 끼우기)를 제공하고, 일상 루틴의 순서를 알려주세요.'),
(8, 357, 389, '프로그램의 세계', '생후 55주경, 복잡한 행동 순서를 실행할 수 있게 됩니다. 전화기를 귀에 대고 말하는 흉내, 인형에게 밥 먹이기 등 역할놀이가 시작됩니다. 고집이 세지고, 원하는 대로 안 되면 크게 울 수 있습니다. 역할놀이 도구를 제공하고, 아이의 시도를 격려하며 기다려 주세요.'),
(9, 420, 455, '원칙의 세계', '생후 64주경, 규칙과 원칙을 이해하기 시작합니다. ''뜨거운 건 만지면 안 돼''와 같은 규칙을 내면화합니다. 경계를 시험하는 행동이 늘어나 양육자가 힘들 수 있습니다. 일관된 규칙을 부드럽게 반복하고, 긍정적 행동에 칭찬과 격려를 아끼지 마세요.'),
(10, 497, 532, '체계의 세계', '생후 75주경, 세상의 체계를 이해하는 큰 도약을 합니다. 가족, 친구, 낯선 사람 등 사회적 관계의 구조를 파악하기 시작합니다. 변덕이 심하고, 한 가지에 오래 집중하지 못할 수 있습니다. 사회적 상호작용을 경험할 기회를 만들어 주고, 감정 표현을 도와주세요.');
INSERT INTO activities (month_id, category, title, content) VALUES
(0, 'development', '원시반사 관찰하기', '신생아는 모로반사(큰 소리에 팔을 벌림), 파악반사(손바닥에 물건을 쥠), 탐색반사(입 주변을 건드리면 고개를 돌림) 등의 원시반사를 보입니다. 이 반사들은 신경계가 정상적으로 발달하고 있다는 신호이며, 생후 3~4개월에 걸쳐 자연스럽게 사라집니다. 아기를 관찰하며 이러한 반사가 잘 나타나는지 확인해 보세요.'),
(0, 'play', '흑백 모빌 보여주기', '신생아의 시력은 약 20~30cm 거리만 초점이 맞습니다. 흑백 대비가 강한 모빌이나 카드를 아기 얼굴에서 20~25cm 거리에 두고 보여주세요. 한 번에 2~3분씩 하루 여러 차례 반복하면 시각 발달에 도움이 됩니다. 아기가 시선을 고정하면 천천히 좌우로 움직여 시선 추적 연습을 해 주세요.'),
(0, 'sleep', '낮과 밤 구별 도와주기', '신생아는 낮과 밤의 구별이 없어 2~3시간 간격으로 깨고 잡니다. 낮에는 밝은 환경에서 활동하고, 밤에는 조명을 어둡게 하고 조용히 수유하여 낮밤 차이를 인식시켜 주세요. 밤 수유 시에는 자극을 최소화하고, 기저귀도 꼭 필요할 때만 갈아주세요. 생후 6~8주경부터 점차 밤에 더 오래 자기 시작합니다.'),
(0, 'food', '수유 가이드 (모유/분유)', '신생아는 2~3시간 간격으로 하루 8~12회 수유가 필요합니다. 모유수유 시 한쪽 유방당 10~15분씩 양쪽을 번갈아 먹이세요. 분유의 경우 1회 30~60ml로 시작하여 아기의 신호에 맞춰 양을 조절합니다. 배고픔 신호(입을 벌리고 고개를 돌림, 손을 입으로 가져감)를 잘 관찰하는 것이 중요합니다.');
INSERT INTO activities (month_id, category, title, content) VALUES
(1, 'development', '시선 고정과 추적 연습', '생후 1개월 아기는 20~30cm 거리의 사물에 초점을 맞출 수 있습니다. 아기 앞에서 밝은 색 장난감이나 얼굴을 천천히 좌우로 움직여 시선 추적을 유도하세요. 양육자의 얼굴을 가까이에서 바라보며 표정을 관찰하는 것도 좋은 자극이 됩니다. 하루 여러 차례 짧게 반복하면 시각-운동 협응 발달에 도움이 됩니다.'),
(1, 'play', '부드러운 소리 자극 놀이', '딸랑이를 아기 귀 옆에서 부드럽게 흔들어 소리 나는 방향으로 고개를 돌리는지 관찰하세요. 다양한 음색의 목소리로 아기에게 말을 걸어주면 청각 발달에 좋습니다. 자장가나 부드러운 음악을 들려주고, 아기의 반응을 관찰하세요. 소리 자극은 너무 크지 않게, 아기가 놀라지 않는 강도로 해 주세요.'),
(1, 'sleep', '수면 루틴 시작하기', '생후 1개월부터 간단한 수면 루틴을 만들어 보세요. 목욕 → 마사지 → 수유 → 재우기 등 매일 같은 순서를 반복하면 아기가 잠잘 시간을 예측할 수 있습니다. 아직 수면 훈련은 이르지만, 졸려하는 신호(눈 비비기, 하품)가 보이면 바로 재우는 것이 좋습니다. 깨시(수면 사이 깨어있는 시간)는 45~60분을 넘기지 않도록 합니다.'),
(1, 'food', '수유 패턴 안정화', '1개월 아기는 1회에 60~120ml를 먹을 수 있으며, 하루 총 6~8회 수유합니다. 모유수유 시 한쪽 당 15~20분씩 충분히 먹이세요. 수유 간격이 2.5~3시간으로 조금씩 규칙적으로 변합니다. 체중 증가가 순조롭다면(주당 150~200g) 수유량이 충분하다는 신호입니다.');
INSERT INTO activities (month_id, category, title, content) VALUES
(2, 'development', '터미타임 본격 늘리기', '생후 2개월부터 터미타임 시간을 본격적으로 늘려갑니다. 터미타임은 출생 직후부터 감독 하에 시작할 수 있지만, 2개월부터는 목 근육이 발달하며 고개를 들 수 있게 됩니다. 수유 후 30분 이상 지난 뒤, 단단한 바닥에 엎드려 놓고 5~10분부터 시작하세요. 아기 앞에서 딸랑이를 흔들거나 말을 걸어 고개를 들도록 유도합니다. 하루 3~5회, 점차 시간을 늘려가며 목과 어깨 근육 발달을 도와주세요.'),
(2, 'play', '얼굴 표정 놀이', '아기와 얼굴을 마주보고 다양한 표정을 지어 보세요. 크게 웃기, 놀란 표정, 혀 내밀기 등을 보여주면 아기가 모방하려 시도합니다. 이 시기 아기는 양육자의 표정을 구별하고 반응할 수 있습니다. 아기가 웃으면 함께 웃어주어 사회적 상호작용의 기초를 다져주세요.'),
(2, 'sleep', '낮잠 패턴 형성', '2개월 아기의 깨시는 약 60~75분입니다. 깨시를 넘기면 과피로해져 오히려 잠들기 어려워집니다. 하품, 눈 비비기, 시선 피하기 등 졸림 신호를 잘 관찰하세요. 낮잠은 하루 4~5회가 적당하며, 어두운 환경과 백색소음이 도움이 됩니다.'),
(2, 'food', '수유량 증가와 성장 급등', '2개월 아기는 1회 100~150ml, 하루 총 600~750ml를 먹습니다. 생후 6주, 3개월 전후로 성장 급등기가 오면 갑자기 자주, 많이 먹으려 합니다. 이때는 아기가 원하는 만큼 충분히 먹이세요. 수유 후 적절한 트림을 시켜주어 역류와 복부 불편을 예방하세요.');
INSERT INTO activities (month_id, category, title, content) VALUES
(3, 'development', '손 뻗어 잡기 연습', '3개월 아기는 눈앞의 물건에 손을 뻗어 잡으려 시도합니다. 아기 손이 닿을 거리에 딸랑이나 부드러운 장난감을 두고 잡아보도록 유도하세요. 이 시기에는 손과 눈의 협응력이 빠르게 발달합니다. 다양한 질감(부드러운, 울퉁불퉁한)의 물건을 경험시켜 주세요.'),
(3, 'play', '거울 놀이', '아기에게 안전한 거울을 보여주세요. 거울 속 자기 모습에 흥미를 보이며 웃거나 소리를 냅니다. 아직 자기 자신이라는 것을 인식하지는 못하지만, 시각 자극과 사회성 발달에 도움이 됩니다. 거울 앞에서 함께 표정 놀이를 하면 더욱 좋습니다.'),
(3, 'sleep', '수면 의식 강화하기', '수면 의식을 더욱 일관되게 유지하세요. 매일 같은 시간, 같은 순서로 진행하면 아기의 체내 시계가 안정됩니다. 이 시기부터 밤 수면이 4~6시간 연속으로 늘어나는 아기가 많습니다. 졸릴 때 눕혀서 스스로 잠드는 연습을 조금씩 시도해 볼 수 있습니다.'),
(3, 'food', '수유 리듬 안정기', '3개월 아기는 1회 120~180ml, 하루 총 750~900ml를 먹습니다. 수유 간격이 3~4시간으로 안정되며, 밤중 수유 횟수가 줄어들기 시작합니다. 모유수유 중이라면 유축을 시작하여 다른 양육자도 수유에 참여할 수 있게 하면 좋습니다. 이 시기에는 아직 이유식을 시작하지 마세요.');
INSERT INTO activities (month_id, category, title, content) VALUES
(4, 'development', '뒤집기 연습 돕기', '4개월 아기는 뒤집기를 시도하기 시작합니다. 엎드린 자세에서 등으로, 또는 등에서 엎드린 자세로 뒤집는 연습을 합니다. 장난감으로 한쪽으로 시선을 유도하여 자연스럽게 뒤집도록 도와주세요. 뒤집기 성공 후에는 안전을 위해 수면 중 뒤집어도 되돌릴 필요는 없지만, 주변 위험 요소를 제거하세요.'),
(4, 'play', '물건 탐색 놀이', '아기가 물건을 잡고 입으로 가져가는 구강 탐색이 활발해집니다. 다양한 크기와 질감의 안전한 장난감을 제공하세요. 치발기, 부드러운 천 장난감, 딸랑이 등이 좋습니다. 입에 넣어도 안전한 것인지 항상 확인하고, 작은 부품이 있는 장난감은 피해 주세요.'),
(4, 'sleep', '수면 퇴행 대비하기', '4개월 전후로 수면 퇴행이 올 수 있습니다. 잘 자던 아기가 갑자기 자주 깨고, 잠들기 어려워합니다. 이는 수면 사이클이 성인과 비슷하게 변하기 때문에 나타나는 정상적인 현상입니다. 일관된 수면 루틴을 유지하고, 과도한 수면 보조(안아서 재우기)를 줄이는 시도를 해 볼 수 있습니다.'),
(4, 'food', '이유식 준비 신호 관찰', '4개월 아기는 아직 이유식을 시작하기에 이를 수 있습니다. 하지만 이유식 시작 신호를 관찰하세요: 목을 완전히 가눔, 혼자 또는 도움 받아 앉기, 음식에 관심을 보임, 혀 내밀기 반사 감소. 1회 150~200ml, 하루 총 800~1000ml를 먹으며, WHO는 6개월까지 완전 모유수유를 권장합니다.');
INSERT INTO activities (month_id, category, title, content) VALUES
(5, 'development', '앉기 연습 시작', '5개월 아기는 지지대를 잡으면 앉는 자세를 유지할 수 있습니다. 아기 주변에 쿠션을 두고 앉히는 연습을 해 보세요. 아직 혼자 앉기는 불안정하므로 항상 뒤에서 지켜봐 주세요. 앉은 자세에서 양손으로 장난감을 잡고 놀 수 있어 탐색의 범위가 넓어집니다.'),
(5, 'play', '물건 옮기기 놀이', '아기가 한 손에서 다른 손으로 물건을 옮기는 것을 연습합니다. 가벼운 블록이나 공을 쥐여주고 양손 간 이동을 유도하세요. 물건을 떨어뜨렸을 때 찾아보는 행동도 나타나며, 이는 대상 영속성의 시작입니다. ''없어졌다 짠!'' 놀이로 인지 발달을 자극해 주세요.'),
(5, 'sleep', '낮잠 통합 시작', '5개월경 낮잠이 하루 3회로 통합되기 시작합니다. 오전, 점심, 오후 낮잠으로 패턴이 잡히며, 깨시는 105~135분입니다. 규칙적인 낮잠 시간을 정해두면 아기의 생체리듬이 안정됩니다. 낮잠 전에도 짧은 수면 의식(기저귀 갈기 → 수면주머니 입히기 → 자장가)을 적용하세요.'),
(5, 'food', '이유식 준비와 첫 시도', '5개월 후반~6개월 사이 이유식 시작 신호가 보이면 준비를 시작합니다. 처음은 쌀미음(10배 죽)으로 1~2수저씩 시작합니다. 알레르기 반응을 관찰하기 위해 새로운 식재료는 3~5일 간격으로 한 가지씩 도입하세요. 이유식은 수유를 대체하는 것이 아니라 보충하는 것이므로, 수유량은 유지합니다.');
INSERT INTO activities (month_id, category, title, content) VALUES
(6, 'development', '혼자 앉기와 상체 조절', '6개월 아기는 도움 없이 혼자 앉을 수 있게 됩니다. 앉은 자세에서 양손을 자유롭게 사용하여 장난감을 탐색합니다. 앉은 상태에서 몸을 앞뒤좌우로 기울이며 균형감각을 발달시킵니다. 다양한 높이에서 물건을 잡아보게 하여 상체 조절력을 길러주세요.'),
(6, 'play', '까꿍놀이와 숨기놀이', '이 시기 아기는 대상 영속성이 발달하여 까꿍놀이를 매우 즐깁니다. 손수건으로 얼굴을 가렸다 보여주거나, 장난감을 천으로 덮고 찾게 하세요. 다양한 변형(뒤에서 나타나기, 상자 속에 숨기기)으로 놀이를 확장할 수 있습니다. 이 놀이는 인지 발달과 사회적 상호작용에 모두 좋습니다.'),
(6, 'sleep', '밤중 수유 줄이기', '6개월이 되면 영양학적으로 밤중 수유 없이 밤새 잘 수 있습니다. 밤중 수유를 줄이려면 잠들기 전 충분한 수유를 하고, 밤에 깼을 때 바로 수유 대신 토닥임으로 재우기를 시도하세요. 깨시는 120~150분이며, 낮잠은 하루 2~3회로 안정됩니다. 일관된 취침 시간(저녁 7~8시)을 정해 지키는 것이 좋습니다.'),
(6, 'food', '이유식 초기 (쌀미음 → 채소 → 과일)', '본격적으로 이유식을 시작합니다. 쌀미음 → 감자, 고구마, 애호박 등 채소 → 사과, 배 등 과일 순서로 도입하세요. 처음에는 10배 죽 농도로, 하루 1회 1~2큰술부터 시작합니다. 새로운 식재료는 3~5일 간격으로 한 가지씩, 알레르기 반응(발진, 설사, 구토)을 관찰하며 진행합니다.');
INSERT INTO activities (month_id, category, title, content) VALUES
(7, 'development', '배밀이와 기기 시작', '7개월 아기는 배밀이(배를 바닥에 대고 이동)나 기기를 시작합니다. 아기 앞에 흥미로운 장난감을 두어 이동을 유도하세요. 기기를 위한 공간을 안전하게 확보하고, 바닥의 위험한 물건을 치워주세요. 기어다니기 시작하면 행동반경이 넓어지므로 안전 게이트와 코너 보호대 설치를 권합니다.'),
(7, 'play', '원인과 결과 놀이', '버튼을 누르면 소리가 나는 장난감, 공을 밀면 굴러가는 놀이 등 인과관계를 경험하는 놀이를 제공하세요. 드럼이나 실로폰을 두드려 소리를 내는 것도 좋습니다. 물건을 떨어뜨리고 주워달라는 놀이를 반복하는데, 이는 인과관계를 확인하는 학습 과정입니다. 짜증내지 마시고 함께 즐겨주세요.'),
(7, 'sleep', '낮잠 2~3회 안정화', '7개월 깨시는 120~180분으로 늘어납니다. 오전 낮잠과 오후 낮잠의 2회 패턴으로 안정되는 아기가 많습니다. 세 번째 낮잠이 짧아지며 자연스럽게 사라질 수 있습니다. 취침 시간이 너무 늦어지지 않도록 마지막 낮잠은 오후 4시 이전에 마치세요.'),
(7, 'food', '이유식 중기 (7배 죽, 단백질 도입)', '이유식 중기로 넘어가며 죽의 농도를 7배 죽으로 높입니다. 두부, 닭가슴살, 소고기 등 단백질 식재료를 도입하세요. 특히 소고기는 철분 보충에 중요하므로 꾸준히 먹여주세요. 하루 2회 이유식으로 늘리고, 수유량은 하루 700~900ml를 유지합니다.');
INSERT INTO activities (month_id, category, title, content) VALUES
(8, 'development', '잡고 서기와 크루징', '8개월 아기는 가구를 잡고 스스로 일어서는 것을 시도합니다. 소파나 테이블을 잡고 옆으로 이동하는 크루징을 하기도 합니다. 무릎 높이의 안정적인 가구를 활용하여 연습할 수 있게 해 주세요. 넘어질 수 있으므로 주변에 딱딱하거나 뾰족한 물건을 치워 안전을 확보하세요.'),
(8, 'play', '용기 놀이 (넣고 빼기)', '통에 물건을 넣고 빼는 놀이를 즐깁니다. 작은 공을 양동이에 넣거나, 블록을 상자에 담는 놀이를 해 보세요. 손가락 소근육 발달과 공간 인지 능력을 길러줍니다. 뚜껑을 열고 닫는 것에도 큰 흥미를 보이므로, 안전한 밀폐 용기를 장난감으로 활용해 보세요.'),
(8, 'sleep', '낮잠 2회 전환', '8개월에는 낮잠이 하루 2회로 안정됩니다. 오전 낮잠(9~10시경)과 오후 낮잠(1~2시경)으로 진행하며, 각 낮잠은 1~2시간이 적당합니다. 깨시가 150~210분으로 늘어나므로 아기 컨디션에 맞춰 조절하세요. 밤잠은 10~12시간 연속 수면이 가능한 시기입니다.'),
(8, 'food', '이유식 중기 (다양한 식감 경험)', '잘게 다진 형태의 이유식으로 식감을 다양하게 경험시킵니다. 손으로 잡아먹을 수 있는 핑거푸드(바나나 조각, 익힌 당근 스틱)를 제공하세요. 하루 2~3회 이유식을 진행하며, 아기가 스스로 먹는 시도를 격려해 주세요. 계란 노른자, 흰살 생선 등 새로운 단백질을 도입하며 알레르기를 관찰합니다.');
INSERT INTO activities (month_id, category, title, content) VALUES
(9, 'development', '미세 운동과 집게 잡기', '9개월 아기는 엄지와 검지를 사용한 집게 잡기(핀서 그립)가 발달합니다. 작은 시리얼 조각이나 작은 물건을 집어보도록 연습하세요(삼킴 위험이 없는 크기). 책 페이지를 넘기려 시도하고, 작은 물건을 정밀하게 조작합니다. 이 시기 소근육 발달은 이후 도구 사용과 글쓰기의 기초가 됩니다.'),
(9, 'play', '간단한 지시 따르기 놀이', '아기가 ''줘'', ''빠이빠이'', ''짝짜꿍'' 같은 간단한 말과 몸짓을 이해하기 시작합니다. 일상에서 ''공 줘'', ''손뼉 짝짝'' 등의 지시를 반복하며 놀아주세요. 손가락으로 가리키기를 시작하면 아기가 가리키는 것에 반응해 주세요. 이런 상호작용이 언어 발달의 중요한 토대가 됩니다.'),
(9, 'sleep', '분리불안과 수면', '9개월경 분리불안이 절정에 달하며 잠자리에서 울 수 있습니다. 취침 전 충분한 스킨십과 안정적인 루틴을 유지해 주세요. 아기가 좋아하는 안전한 애착 물건(작은 인형, 수건)을 수면 파트너로 제공하면 도움이 됩니다. 밤에 깨서 울 때는 잠시 기다렸다 가서 안심시키는 방법을 시도해 보세요.'),
(9, 'food', '이유식 후기 (5배 죽, 3회식)', '이유식을 하루 3회로 늘리고, 죽의 농도를 5배 죽(진밥)으로 높입니다. 다양한 식재료를 골고루 사용하여 균형 잡힌 영양을 제공하세요. 핑거푸드를 더 적극적으로 제공하여 자기 주도 식사를 연습합니다. 수유량은 하루 600~800ml로 자연스럽게 줄어들며, 간식도 하루 1~2회 제공할 수 있습니다.');
INSERT INTO activities (month_id, category, title, content) VALUES
(10, 'development', '혼자 서기 시도와 첫 걸음 준비', '10개월 아기는 물건을 잡지 않고 혼자 서는 것을 시도합니다. 몇 초간 균형을 잡고 서 있다가 주저앉기를 반복합니다. 아기 앞에서 두 팔을 벌리고 한두 발 걸어오도록 유도해 보세요. 맨발로 다양한 바닥을 경험하게 하면 발바닥 감각과 균형감 발달에 좋습니다.'),
(10, 'play', '쌓기와 무너뜨리기 놀이', '블록이나 컵을 쌓고 무너뜨리는 놀이를 즐깁니다. 2~3개 블록을 쌓아주면 아기가 무너뜨리며 인과관계를 학습합니다. 점차 아기가 직접 쌓는 시도를 하게 됩니다. 공 굴리기, 자동차 밀기 등 간단한 역할놀이도 시작해 보세요.'),
(10, 'sleep', '안정적인 수면 스케줄', '10개월에는 수면 스케줄이 매우 안정됩니다. 밤 10~12시간, 낮잠 2회(총 2~3시간)가 일반적입니다. 깨시 180~240분을 지켜주되, 과피로 신호를 놓치지 마세요. 일관된 취침 시간과 기상 시간을 유지하면 아기의 수면의 질이 높아집니다.'),
(10, 'food', '다양한 질감과 자기 주도 식사', '이유식의 질감을 더 거칠게 하여 씹는 연습을 합니다. 부드러운 밥알이 있는 형태로 진행하고, 핑거푸드의 종류를 다양화하세요. 아기에게 숟가락을 쥐여주어 스스로 먹는 연습을 격려합니다. 컵으로 물 마시기도 연습하세요. 흘리더라도 자기 주도 식사 경험이 중요합니다.');
INSERT INTO activities (month_id, category, title, content) VALUES
(11, 'development', '크루징과 독립 보행 준비', '11개월 아기는 가구를 잡고 이동하는 크루징이 능숙해집니다. 한 손만 잡아도 걸을 수 있는 아기도 있습니다. 밀어서 걷는 장난감(푸시 워커)을 제공하면 걷기 연습에 도움이 됩니다. 보행기(베이비 워커)보다는 자연스럽게 걷기를 배우도록 하는 것이 발달에 좋습니다.'),
(11, 'play', '모방 놀이와 역할 놀이', '어른의 행동을 따라하는 모방 놀이가 활발해집니다. 전화기를 귀에 대기, 빗으로 머리 빗기, 컵으로 마시는 시늉 등을 합니다. 장난감 주방세트, 인형 등을 활용한 간단한 역할놀이를 제공하세요. 이러한 모방은 사회성과 인지 발달의 중요한 단계입니다.'),
(11, 'sleep', '낮잠 1~2회 전환기', '일부 아기는 낮잠이 하루 1회로 줄어들기 시작합니다. 오전 낮잠이 짧아지거나 거부하는 모습이 보이면 1회 낮잠으로 전환을 고려해 보세요. 단, 대부분의 아기는 아직 2회 낮잠이 필요합니다. 전환 시 취침 시간을 30분 앞당겨 피로 누적을 방지하세요.'),
(11, 'food', '유아식 전환 준비', '이유식에서 유아식으로 전환을 준비하는 시기입니다. 진밥 또는 부드러운 일반 밥을 먹을 수 있습니다. 가족과 함께 식사하며 다양한 음식을 경험시키세요. 하루 3회 식사 + 1~2회 간식, 수유량은 하루 500~700ml로 줄어듭니다. 돌 전까지 꿀, 생우유는 피해주세요.');
INSERT INTO activities (month_id, category, title, content) VALUES
(12, 'development', '첫 걸음과 독립 보행', '12개월 전후로 많은 아기가 첫 걸음을 뗍니다. 처음에는 비틀거리며 몇 발자국 걷다가 주저앉지만, 빠르게 안정됩니다. 아직 걷지 않더라도 정상이며, 15~18개월까지 걷기를 시작하면 됩니다. 안전한 환경에서 자유롭게 걷기를 연습하게 하고, 넘어져도 크게 반응하지 마세요.'),
(12, 'play', '간단한 퍼즐과 구분 놀이', '간단한 도형 맞추기 퍼즐이나 링 끼우기 장난감을 제공하세요. 크기 순서대로 쌓기, 모양 맞추기 등으로 문제 해결 능력을 키워줍니다. 그림책을 함께 보며 사물의 이름을 알려주고, ''강아지 어디 있어?''라고 물어보세요. 지적 호기심이 폭발하는 시기이므로 다양한 탐색 기회를 만들어 주세요.'),
(12, 'sleep', '안정적 수면 패턴 유지', '12개월에는 밤 11~12시간, 낮잠 1~2회(총 2~3시간)가 적당합니다. 대부분의 아기가 밤새 깨지 않고 잘 수 있습니다. 걷기 시작하면서 활동량이 늘어 수면의 질이 좋아집니다. 취침 시간(저녁 7~8시)과 기상 시간(아침 6~7시)을 일관되게 유지하세요.'),
(12, 'food', '유아식 전환과 돌 이후 식이', '돌이 지나면 생우유(하루 400~500ml)를 시작할 수 있습니다. 성인 식사와 비슷하지만 싱겁게 조리하여 함께 먹습니다. 하루 3끼 식사 + 2회 간식이 기본 패턴입니다. 다양한 식재료를 경험시키되, 질식 위험이 있는 음식(견과류 통째, 포도알 통째, 떡)은 주의하세요.');
